class Solution:
    def vowelStrings(self, words, queries):
        vowels = set('aeiou')
        res = []
        for l, r in queries:
            cnt = 0
            for i in range(l, r + 1):
                w = words[i]
                if w[0] in vowels and w[-1] in vowels:
                    cnt += 1
            res.append(cnt)
        return res

