class Solution:
    def vowelStrings(self, words, queries):
        vowels = set('aeiou')
        n = len(words)
        prefix = [0] * (n + 1)
        for i, w in enumerate(words):
            flag = 1 if (w[0] in vowels and w[-1] in vowels) else 0
            prefix[i + 1] = prefix[i] + flag
        return [prefix[r + 1] - prefix[l] for l, r in queries]

